# plc_analyze.py
# Parses the null-delimited memory block data to locate the MD5 hash
# Run after plc_dump.py — paste block 0 and block 1 hex here

BLOCK0_HEX = ""

BLOCK1_HEX = ""

data0 = bytes.fromhex(BLOCK0_HEX)
data1 = bytes.fromhex(BLOCK1_HEX)

def parse_segments(data, label):
    segments = data.split(b'\x00')
    print(f"\n[*] {label} — null-delimited segments:")
    for i, seg in enumerate(segments):
        if len(seg) == 0:
            continue
        tag = "  <== 16 BYTES (MD5 CANDIDATE!)" if len(seg) == 16 else ""
        try:
            ascii_repr = f"  ascii='{seg.decode('ascii')}'"
        except:
            ascii_repr = ""
        print(f"  [{i:3d}] len={len(seg):3d}  hex={seg.hex():<40s}{tag}{ascii_repr}")

parse_segments(data0, "Block 0")
parse_segments(data1, "Block 1")

print("\n[*] Summary:")
print(f"  Block 0: {len(data0)} bytes, {data0.count(0):} null bytes")
print(f"  Block 1: {len(data1)} bytes, {data1.count(0):} null bytes")

# The 16-byte MD5 candidate in Block 1
candidate = data1.split(b'\x00')[0]
if len(candidate) == 16:
    print(f"\n[+] MD5 hash found at Block 1, offset 0: {candidate.hex()}")
